            <button 
               onClick={prevSlide}
               disabled={state.currentStepIndex === 0}
               className="w-14 h-14 rounded-2xl bg-slate-800 hover:bg-slate-700 disabled:opacity-30 disabled:cursor-not-allowed flex items-center justify-center text-slate-200 border border-slate-700 transition-all active:scale-95"
            >
               <ChevronLeft size={28} />
            </button>
            <button 
               onClick={nextSlide}
               disabled={!nextStep}
               className="w-20 h-14 rounded-2xl bg-indigo-600 hover:bg-indigo-500 disabled:opacity-50 flex items-center justify-center text-white shadow-lg shadow-indigo-900/30 transition-all active:scale-95"
            >
