         {/* Center: Point Pad (Student Quick List) */}
         <div className="flex-1 px-4 overflow-x-auto no-scrollbar">
            <div className="flex items-center gap-3 min-w-min mx-auto">
               {state.students.map((student) => (
                  <button 
                     key={student.id}
