                     }}
                     className={`group flex flex-col items-center gap-1 min-w-[60px] p-2 rounded-xl transition-all active:scale-95 ${activePointStudentId === student.id ? 'bg-indigo-900/50 ring-2 ring-indigo-500' : 'hover:bg-slate-800'}`}
                  >
                     <div className="w-10 h-10 rounded-full bg-slate-800 border border-slate-700 flex items-center justify-center text-lg shadow-sm group-hover:border-green-500/50 group-hover:shadow-[0_0_10px_rgba(34,197,94,0.2)] transition-all relative">
                        {student.avatar}
                        <div className="absolute -top-1 -right-1 w-4 h-4 bg-slate-700 rounded-full flex items-center justify-center text-[8px] font-bold text-slate-300 border border-slate-600">
                           {student.points}
                        </div>
                        {state.lastAction?.type === 'MASS_PENALTY' && (
                           <div className="absolute inset-0 flex items-center justify-center text-red-500 font-black text-xs animate-ping">
                              -5
                           </div>
