               ))}
            </div>
         </div>

         {/* Right: God Tools (Now Switch Tabs) */}
         <div className="flex items-center gap-3 pl-4 border-l border-slate-800">
            <button 
               onClick={() => setActiveSidebarTab(activeSidebarTab === 'sounds' ? 'notes' : 'sounds')}
