            >
               <Volume2 size={20} />
               <span className="text-[9px] font-bold uppercase mt-1">Sound</span>
            </button>
            <button 
               onClick={() => setActiveSidebarTab(activeSidebarTab === 'wheel' ? 'notes' : 'wheel')}
               className={`flex flex-col items-center justify-center w-16 h-14 rounded-xl border transition-all active:scale-95 ${activeSidebarTab === 'wheel' ? 'bg-yellow-500 border-yellow-400 text-black' : 'bg-slate-800 border-slate-700 text-yellow-400 hover:bg-slate-700'}`}
            >
               <Zap size={20} />
               <span className="text-[9px] font-bold uppercase mt-1">Wheel</span>
            </button>
            <button 
               onClick={() => setActiveSidebarTab(activeSidebarTab === 'groups' ? 'notes' : 'groups')}
               className={`flex flex-col items-center justify-center w-16 h-14 rounded-xl border transition-all active:scale-95 ${activeSidebarTab === 'groups' ? 'bg-purple-600 border-purple-500 text-white' : 'bg-slate-800 border-slate-700 text-purple-400 hover:bg-slate-700'}`}
            >
               <LayoutGrid size={20} />
               <span className="text-[9px] font-bold uppercase mt-1">Group</span>
            </button>
            <button 
               onClick={toggleQuietMode}
               className={`
                  flex flex-col items-center justify-center w-16 h-14 rounded-xl border transition-all active:scale-95
                  ${state.quietModeActive ? 'bg-red-500 text-white border-red-400 animate-pulse' : 'bg-rose-500/10 hover:bg-rose-500/20 text-rose-500 border-rose-500/20'}
               `}
            >
               {state.quietModeActive ? <Activity size={20} className="animate-bounce" /> : <Bell size={20} />}
               <span className="text-[9px] font-bold uppercase mt-1">{state.quietModeActive ? 'Active' : 'Quiet'}</span>
