import React, { useState, useRef, useEffect } from 'react';
import { ChevronLeft, MoreHorizontal, Headphones, Mic, Play, RotateCcw, StopCircle } from 'lucide-react';

interface DubbingStudioProps {
  onBack: () => void;
}

const DubbingStudio: React.FC<DubbingStudioProps> = ({ onBack }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [progress, setProgress] = useState(0); // 0-100 for display

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
  const recordingTimerRef = useRef<number | null>(null);

  useEffect(() => {
    // Cleanup URL on unmount
    return () => {
      if (audioUrl) URL.revokeObjectURL(audioUrl);
      if (recordingTimerRef.current) clearInterval(recordingTimerRef.current);
    };
  }, [audioUrl]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);

      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/wav' });
        const url = URL.createObjectURL(audioBlob);
        setAudioUrl(url);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setAudioUrl(null); // Clear previous
      setProgress(0);

      // Simulate progress bar for recording limit (e.g. 10s)
      recordingTimerRef.current = window.setInterval(() => {
         setProgress(p => {
            if (p >= 100) {
               stopRecording();
               return 100;
            }
            return p + 1;
         });
      }, 100); // 10s duration approx

    } catch (err) {
      console.error("Mic Error:", err);
      alert("Microphone access denied.");
    }
  };

  const stopRecording = () => {
