export interface ScannedLessonData {
  title: string;
  vocabulary: Array<{ term: string; def: string }>;
  grammar: Array<{ rule: string; example: string }>;
}

export const analyzeTextbookPage = async (imageBase64: string): Promise<ScannedLessonData | null> => {
  try {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Stronger reasoning for OCR/Analysis
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: imageBase64
            }
          },
          {
            text: `
            You are an expert ESL Curriculum Designer.
            **CRITICAL INSTRUCTION:** You must analyze the PROVIDED IMAGE. Do NOT invent data. Do NOT use examples about airports or travel unless they are in the image.

            **STEP 1: VISUAL AUDIT**
            First, look at the image.
            - What is the title text? (e.g., "Unit 6: A Day Out")
            - What images are visible? (e.g., Giraffes, Snakes, Bus)
            - IF YOU CANNOT SEE THE IMAGE, RETURN ERROR.

            **STEP 2: EXTRACTION**
            Extract specific content from the image:
            1. **Vocabulary:** Extract words specifically labeled or illustrated.
            2. **Grammar:** If there is a grammar box, extract the rule.

            **STEP 3: JSON GENERATION**
            Map this content into the following JSON structure.
            `
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING, description: "The unit title visible on the page" },
            vocabulary: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  term: { type: Type.STRING },
                  def: { type: Type.STRING, description: "Simple definition for kids" }
                }
              }
            },
            grammar: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  rule: { type: Type.STRING },
                  example: { type: Type.STRING }
                }
              }
            }
          },
          required: ["title", "vocabulary"]
        }
      }
    });

    const text = response.text;
    if (!text) return null;
    return JSON.parse(text) as ScannedLessonData;
  } catch (error) {
    console.error("Gemini Scan Error:", error);
    // Rethrow so the UI knows to fallback or show error
    throw error;
  }
};

