// Mock Student Progress DB
let STUDENT_PROGRESS = {
  completedUnitIds: ['u0'] as string[], // u0 doesn't exist, just a placeholder
  currentUnitId: 'u1',
  xp: 1250,
  streak: 12
};

// In-memory storage for the session
let MOCK_DB = [...INITIAL_DB];

export const MockEngine = {
  // Simulate Network Request
  fetchUnits: async (): Promise<LessonUnit[]> => {
    await new Promise(resolve => setTimeout(resolve, 600)); // 600ms latency

    // Sync status based on progress
    return MOCK_DB.map(unit => {
      if (STUDENT_PROGRESS.completedUnitIds.includes(unit.id)) {
        return { ...unit, status: 'Completed' };
      }
      if (unit.id === STUDENT_PROGRESS.currentUnitId) {
        return { ...unit, status: 'Active' };
      }
      // Simple logic: if previous unit is complete, this one is active? 
      // For now, keep DB status but override if current
      return unit;
    });
  },

  // Simulate AI Processing
  simulateScan: async (fileName: string): Promise<LessonUnit> => {
    // The "Analysis" component handles the visual delay, so this returns quickly after called
    await new Promise(resolve => setTimeout(resolve, 500)); 

    const newUnit: LessonUnit = {
      id: `u_${Date.now()}`,
      title: `Scanned: ${fileName.split('.')[0] || 'Textbook Upload'}`,
      level: 'AI Detected',
      status: 'Draft',
      lessons: 1,
      coverImage: 'https://images.unsplash.com/photo-1497633762265-9d179a990aa6?q=80&w=800', // Library book image
      lastUpdated: 'Just now',
      flow: MOCK_LESSON_FLOW // Reuse the complex flow for the prototype
    };

    MOCK_DB.unshift(newUnit); // Add to top of list
    return newUnit;
  },

  // Smart Mock Data Generation based on Context
  generateMockLessonData: (filename: string): MockScanResult => {
    const name = filename.toLowerCase();

    if (name.includes('space') || name.includes('planet')) {
      return {
        title: "Unit: Space Explorers",
        vocab: [
          { id: 1, type: 'vocab', term: 'Astronaut', def: 'A person trained to travel in a spacecraft.', status: 'verified' },
          { id: 2, type: 'vocab', term: 'Rocket', def: 'A vehicle used to travel to space.', status: 'verified' },
          { id: 3, type: 'vocab', term: 'Planet', def: 'A large body in space that orbits a star.', status: 'review' },
          { id: 4, type: 'vocab', term: 'Star', def: 'A ball of burning gas in space.', status: 'verified' }
        ]
      };
    } 

    if (name.includes('zoo') || name.includes('animal') || name.includes('safari') || name.includes('jungle')) {
      return {
        title: "Unit: At the Zoo",
        vocab: [
          { id: 1, type: 'vocab', term: 'Giraffe', def: 'A tall animal with a long neck.', status: 'verified' },
          { id: 2, type: 'vocab', term: 'Elephant', def: 'A large animal with a trunk.', status: 'verified' },
          { id: 3, type: 'vocab', term: 'Zebra', def: 'A horse-like animal with stripes.', status: 'verified' },
          { id: 4, type: 'vocab', term: 'Lion', def: 'A large wild cat.', status: 'review' }
        ]
      };
    }

    // Default Fallback (Airport)
    return {
      title: "Unit: Travel Plans",
      vocab: [
        { id: 1, type: 'vocab', term: 'Passport', def: 'A document needed for international travel.', status: 'verified' },
        { id: 2, type: 'vocab', term: 'Luggage', def: 'Bags and suitcases used for carrying things.', status: 'verified' },
        { id: 3, type: 'vocab', term: 'Airport', def: 'A place where airplanes take off and land.', status: 'review' },
        { id: 4, type: 'vocab', term: 'Ticket', def: 'A piece of paper that shows you paid for a journey.', status: 'verified' }
      ]
    };
  },

  getUnitById: (id: string): LessonUnit | undefined => {
    return MOCK_DB.find(u => u.id === id);
  },

  // Update Lesson Data (Persistence)
  updateUnit: async (id: string, updates: Partial<LessonUnit>): Promise<void> => {
    await new Promise(resolve => setTimeout(resolve, 300));
    MOCK_DB = MOCK_DB.map(u => u.id === id ? { ...u, ...updates, lastUpdated: 'Just now' } : u);
  },

  // Student Progress
  unlockNextUnit: async (currentId: string): Promise<void> => {
    await new Promise(resolve => setTimeout(resolve, 300));
    if (!STUDENT_PROGRESS.completedUnitIds.includes(currentId)) {
        STUDENT_PROGRESS.completedUnitIds.push(currentId);
    }

    // Find next unit to unlock
    const idx = MOCK_DB.findIndex(u => u.id === currentId);
    if (idx !== -1 && idx < MOCK_DB.length - 1) {
        const nextUnit = MOCK_DB[idx + 1];
        STUDENT_PROGRESS.currentUnitId = nextUnit.id;
        // Update DB status to reflect unlock
        nextUnit.status = 'Active'; 
    }
  },

  getStudentProgress: () => STUDENT_PROGRESS
};

import React, { useState, useRef } from 'react';
import { UploadCloud, Check, X, ArrowRight, Loader2, FileText, Trash2, Plus } from 'lucide-react';
import { MockEngine } from '../../services/MockEngine';
import { analyzeTextbookPage } from '../../services/geminiService';
import { useSession } from '../../store/SessionContext';
import ReviewContent from './ReviewContent';
import AIAnalysis from './AIAnalysis';

interface UploadTextbookProps {
  onFinish?: () => void;
}

const UploadTextbook: React.FC<UploadTextbookProps> = ({ onFinish }) => {
  const { loadUnits } = useSession();
  const [isDragging, setIsDragging] = useState(false);
  const [isScanning, setIsScanning] = useState(false);
  const [showReview, setShowReview] = useState(false);

  // Store actual File objects now
  const [files, setFiles] = useState<File[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Store scanned data to pass to review
  const [scannedData, setScannedData] = useState<any>(null);

  const startScan = async () => {
    if (files.length === 0) return;
    setIsScanning(true);

    // Trigger visual analysis steps
    // The actual AI call happens inside handleAIComplete or in parallel?
    // Let's do it in parallel but wait for the visual timer to look good.
  };

  const handleAIComplete = async () => {
    const file = files[0];
    const fileName = file?.name || "Chapter 4 - Rainforests.pdf";
    let aiResult = null;

    try {
      // 1. Try Real AI Scan if file is an image
      if (file && file.type.startsWith('image/')) {
         const base64 = await fileToBase64(file);
         // Strip prefix for API
         const base64Data = base64.split(',')[1];
         aiResult = await analyzeTextbookPage(base64Data);
      }
    } catch (e) {
      console.log("AI Scan unavailable or failed, falling back to smart mock.", e);
    }

    // 2. Fallback to Smart Mock if AI failed or not an image
    if (!aiResult) {
       const mockData = MockEngine.generateMockLessonData(fileName);
       aiResult = {
          title: mockData.title,
          vocabulary: mockData.vocab.map(v => ({ term: v.term, def: v.def }))
       };
    }

    // 3. Persist to Mock DB
    await MockEngine.simulateScan(fileName);
    await loadUnits();

    setScannedData(aiResult);
    setIsScanning(false);
    setShowReview(true);
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = error => reject(error);
    });
  };

  const handlePublish = () => {
    // In a real app, this would save to DB. 
    // Here we just finish the flow.
    onFinish?.();
  };

  const handleDragEnter = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    // Prevent flickering: only disable if we are actually leaving the container
    if (e.currentTarget.contains(e.relatedTarget as Node)) return;
    setIsDragging(false);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    // Ensure drag effect is copy
    e.dataTransfer.dropEffect = 'copy';
    setIsDragging(true);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      const newFiles = Array.from(e.dataTransfer.files);
      setFiles(prev => [...prev, ...newFiles]);
    }
  };

  const handleBrowseClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newFiles = Array.from(e.target.files);
      setFiles(prev => [...prev, ...newFiles]);
    }
    // Reset input so same file can be selected again if needed (though we append now)
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removeFile = (index: number) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  const formatSize = (bytes: number) => {
    if (bytes === 0) return '0 Bytes';
    const k = 1024;
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
  };

  if (isScanning) {
    return <AIAnalysis onCancel={() => setIsScanning(false)} onComplete={handleAIComplete} />;
  }

  if (showReview) {
    return <ReviewContent onBack={() => setShowReview(false)} onPublish={handlePublish} initialData={scannedData} />;
  }

  return (
    <div className="flex-1 p-8 overflow-auto flex gap-8">
      {/* Main Upload Area */}
      <div className="flex-1 max-w-4xl">
         <div className="flex items-center gap-4 mb-8">
            <div className={`flex items-center text-sm font-bold text-slate-500`}>
               <span className="w-8 h-8 rounded-full bg-teacher-primary text-white flex items-center justify-center mr-2">1</span>
               Upload
            </div>
            <div className="w-12 h-0.5 bg-slate-200"></div>
            <div className={`flex items-center text-sm font-bold text-slate-300`}>
               <span className="w-8 h-8 rounded-full bg-slate-100 text-slate-400 flex items-center justify-center mr-2">2</span>
               Processing
            </div>
            <div className="w-12 h-0.5 bg-slate-200"></div>
            <div className="flex items-center text-sm font-bold text-slate-300">
               <span className="w-8 h-8 rounded-full bg-slate-100 text-slate-400 flex items-center justify-center mr-2">3</span>
               Review
            </div>
         </div>

         <h1 className="text-3xl font-display font-bold text-slate-800 mb-2">Let's digitize your textbook</h1>
         <p className="text-slate-500 mb-8">Upload scanned pages or PDFs to automatically generate interactive lessons.</p>

         <div 
            className={`border-4 border-dashed rounded-[2rem] min-h-[400px] flex flex-col items-center justify-center transition-all duration-300 relative cursor-pointer
               ${isDragging ? 'border-teacher-primary bg-emerald-50 scale-[1.02]' : 'border-slate-200 hover:border-teacher-primary hover:bg-slate-50'}
            `}
            onDragEnter={handleDragEnter}
            onDragLeave={handleDragLeave}
            onDragOver={handleDragOver}
            onDrop={handleDrop}
            onClick={files.length === 0 ? handleBrowseClick : undefined} // Only trigger browse on container click if empty, otherwise we rely on the specific "Add" button
         >
            <input 
               type="file" 
               ref={fileInputRef} 
               className="hidden" 
               onChange={handleFileSelect} 
               accept=".jpg,.jpeg,.png,.pdf"
               multiple
            />

            {files.length > 0 ? (
               <div className="w-full h-full p-8 flex flex-col">
                  <div className="flex-1 overflow-y-auto max-h-[320px] space-y-3 pr-2 custom-scrollbar">
                     {files.map((file, index) => (
                        <div key={index} className="flex items-center justify-between bg-white p-4 rounded-xl shadow-sm border border-slate-200 animate-scale-in group">
                           <div className="flex items-center gap-4 overflow-hidden">
                              <div className="w-12 h-12 bg-blue-50 text-blue-500 rounded-lg flex items-center justify-center shrink-0">
                                 <FileText size={24} />
                              </div>
                              <div className="min-w-0">
                                 <h4 className="font-bold text-slate-700 truncate">{file.name}</h4>
                                 <p className="text-xs text-slate-400">{formatSize(file.size)}</p>
                              </div>
                           </div>

                           <div className="flex items-center gap-3">
                              <span className="flex items-center gap-1 text-xs font-bold text-emerald-600 bg-emerald-50 px-2 py-1 rounded-full">
                                 <Check size={12} strokeWidth={3} /> Ready
                              </span>
                              <button 
                                 onClick={(e) => { e.stopPropagation(); removeFile(index); }}
                                 className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                              >
                                 <Trash2 size={18} />
                              </button>
                           </div>
                        </div>
                     ))}
                  </div>

                  {/* Add More Button inside the zone */}
                  <div className="mt-6 flex justify-center">
                     <button 
                        onClick={(e) => { e.stopPropagation(); handleBrowseClick(); }}
                        className="flex items-center gap-2 text-slate-500 font-bold hover:text-teacher-primary transition-colors bg-white/50 px-4 py-2 rounded-lg hover:bg-white border border-transparent hover:border-slate-200"
                     >
                        <Plus size={20} /> Add another file
                     </button>
                  </div>
               </div>
            ) : (
               <div className="pointer-events-none flex flex-col items-center">
                  <div className="w-24 h-24 bg-white rounded-full shadow-lg flex items-center justify-center mb-6 text-teacher-primary">
                      <UploadCloud size={48} />
                  </div>
                  <h3 className="text-xl font-bold text-slate-800 mb-2">Drag & Drop files here</h3>
                  <p className="text-slate-400 mb-8">or click to browse your computer</p>

                  <div className="flex gap-3">
                      <span className="px-3 py-1 bg-slate-100 text-slate-500 rounded text-xs font-bold uppercase tracking-wider">JPG</span>
                      <span className="px-3 py-1 bg-slate-100 text-slate-500 rounded text-xs font-bold uppercase tracking-wider">PNG</span>
                      <span className="px-3 py-1 bg-slate-100 text-slate-500 rounded text-xs font-bold uppercase tracking-wider">PDF</span>
                  </div>
               </div>
            )}
         </div>

         <div className="flex justify-between items-center mt-8">
            <div className="text-xs text-slate-400 flex items-center gap-2">
               <span className="w-4 h-4 rounded-full bg-slate-200 flex items-center justify-center font-serif text-[10px]">i</span>
               Max file size: 50MB per file
            </div>
            <button 
              onClick={startScan}
              disabled={files.length === 0}
              className={`px-8 py-4 rounded-xl font-bold text-lg shadow-lg flex items-center gap-2 transition-all
                 ${files.length > 0 
                    ? 'bg-teacher-primary text-white hover:scale-105 shadow-emerald-200' 
                    : 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none'}
              `}
            >
                Start AI Scan <ArrowRight size={20} />
            </button>
         </div>
      </div>

      {/* Sidebar Helper */}
      <div className="w-80 space-y-6">
         {/* Tips Card */}
         <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
            <h3 className="font-bold text-slate-800 mb-4 flex items-center gap-2">
               <div className="w-2 h-2 rounded-full bg-yellow-400"></div>
               Scanning Tips
            </h3>
            <ul className="space-y-4">
               <li className="flex gap-3 text-sm text-slate-600">
                  <div className="w-5 h-5 rounded-full bg-green-100 text-green-600 flex items-center justify-center shrink-0"><Check size={12} /></div>
                  Ensure good lighting and no shadows on the page.
               </li>
               <li className="flex gap-3 text-sm text-slate-600">
                  <div className="w-5 h-5 rounded-full bg-green-100 text-green-600 flex items-center justify-center shrink-0"><Check size={12} /></div>
                  Keep pages flat. Use a book clamp if needed.
               </li>
               <li className="flex gap-3 text-sm text-slate-600">
                  <div className="w-5 h-5 rounded-full bg-red-100 text-red-600 flex items-center justify-center shrink-0"><X size={12} /></div>
                  Avoid blurry text or fingers covering words.
               </li>
            </ul>
         </div>

         {/* Recent Scans */}
         <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100">
             <h3 className="font-bold text-slate-800 mb-4">Recent Scans</h3>
             <div className="space-y-3">
                {[1,2,3].map(i => (
                  <div key={i} className="flex gap-3 items-center group cursor-pointer">
                     <div className="w-12 h-16 bg-slate-100 rounded-lg overflow-hidden border border-slate-200">
