export const MockEngine = {
  // Simulate Network Request
  fetchUnits: async (): Promise<LessonUnit[]> => {
    await new Promise(resolve => setTimeout(resolve, 300));
    return MOCK_DB;
  },

  // Simulate AI Processing with Smart Context
  simulateScan: async (fileName: string): Promise<LessonUnit> => {
    await new Promise(resolve => setTimeout(resolve, 1500)); // Processing delay

    // Generate context-aware mock assets
    const isZoo = fileName.toLowerCase().includes('zoo') || fileName.toLowerCase().includes('animal');
    const topic = isZoo ? 'Zoo Animals' : 'General Topic';

    const mockAssets: ScannedAsset[] = isZoo ? [
       { id: 'a1', type: 'vocab', status: 'pending', content: { term: 'Lion', def: 'King of the jungle', image: '🦁' } },
       { id: 'a2', type: 'vocab', status: 'pending', content: { term: 'Zebra', def: 'Striped horse', image: '🦓' } },
       { id: 'a3', type: 'grammar', status: 'pending', content: { rule: 'Present Continuous', example: 'The lion is sleeping.' } }
    ] : [
       { id: 'a1', type: 'vocab', status: 'pending', content: { term: 'Concept A', def: 'Definition A', image: '📝' } },
       { id: 'a2', type: 'text', status: 'pending', content: { text: 'Chapter 1 Introduction...' } }
    ];

    const newUnit: LessonUnit = {
      id: `u_${Date.now()}`,
      title: isZoo ? 'Unit 4: At The Zoo' : `Scanned: ${fileName.split('.')[0]}`,
      level: 'AI Detected',
      status: 'Processing', // Starts in processing
      lessons: 1,
      coverImage: isZoo ? 'https://images.unsplash.com/photo-1596727147705-01a29cce9ac3?q=80&w=800' : 'https://images.unsplash.com/photo-1497633762265-9d179a990aa6?q=80&w=800',
      lastUpdated: 'Just now',
      flow: [], // Empty flow initially
      scannedAssets: mockAssets,
      topic: topic
    };

    MOCK_DB.unshift(newUnit);
    return newUnit;
  },

  getUnitById: (id: string): LessonUnit | undefined => {
    return MOCK_DB.find(u => u.id === id);
  },

  updateUnit: async (id: string, updates: Partial<LessonUnit>): Promise<void> => {
    await new Promise(resolve => setTimeout(resolve, 200));
    MOCK_DB = MOCK_DB.map(u => u.id === id ? { ...u, ...updates, lastUpdated: 'Just now' } : u);
  },

  unlockNextUnit: async (currentId: string): Promise<void> => {
    if (!STUDENT_PROGRESS.completedUnitIds.includes(currentId)) {
        STUDENT_PROGRESS.completedUnitIds.push(currentId);
    }
    const idx = MOCK_DB.findIndex(u => u.id === currentId);
    if (idx !== -1 && idx < MOCK_DB.length - 1) {
        const nextUnit = MOCK_DB[idx + 1];
        STUDENT_PROGRESS.currentUnitId = nextUnit.id;
        nextUnit.status = 'Active'; 
    }
  },

  getStudentProgress: () => STUDENT_PROGRESS
};

