export const analyzeTextbookPage = async (imageBase64: string): Promise<LessonBlueprint | null> => {
  try {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // Using Pro for complex reasoning
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: imageBase64
            }
          },
          {
            text: `
            You are an Expert Educational Game Designer.
            Your goal is to convert a static textbook page image into a JSON Blueprint for an interactive tablet app.

            **STEP 1: VISUAL SEGMENTATION**
            Analyze the image layout. Break it down into distinct 'Activities'.
            - If you see a Musical Note icon 🎵 or 'Sing', classify as 'MEDIA_PLAYER' (Song).
            - If you see a Comic Strip (panels) or dialogue, classify as 'STORY_STAGE'.
            - If you see a Grammar Box (e.g., 'Gracie's Grammar' or tables), classify as 'GRAMMAR_BOARD'.
            - If you see a Maze, Matching Lines, or 'Find the...', classify as 'GAME_ARENA'.
            - If you see a labeled scene (big picture with words) or vocabulary list, classify as 'FOCUS_CARDS'.

            **STEP 2: DATA EXTRACTION (Context-Aware)**
            Do not just extract text. Extract the *Logic*.
            *   For Grammar: Extract the pattern (e.g., ["There's a", "There isn't a"]) and examples.
            *   For Mazes/Puzzles: Extract the logical pairs (e.g., [["Polar Bear", "Ice"], ["Camel", "Desert"]]).
            *   For Songs: Extract a specific search query I can use to find this song or a similar one on YouTube.

            **STEP 3: JSON GENERATION**
            Return this exact structure. DO NOT invent data. If the page is about Animals, the JSON MUST be about Animals.
            `
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            unit_title: { type: Type.STRING, description: "The unit title extracted from the page header" },
            timeline: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  type: { type: Type.STRING, enum: ['MEDIA_PLAYER', 'FOCUS_CARDS', 'GRAMMAR_BOARD', 'GAME_ARENA', 'STORY_STAGE'] },
                  title: { type: Type.STRING, description: "A catchy title for this specific activity" },
                  search_query: { type: Type.STRING, description: "For MEDIA_PLAYER: A specific youtube search query for the song" },
                  items: { 
                    type: Type.ARRAY, 
                    items: { 
                      type: Type.OBJECT, 
                      properties: { 
                        word: { type: Type.STRING }, 
                        context: { type: Type.STRING } 
                      } 
                    },
                    description: "For FOCUS_CARDS: List of vocab words"
                  },
                  rule: { type: Type.STRING, description: "For GRAMMAR_BOARD: The main rule (e.g. 'Present Simple')" },
                  examples: { 
                    type: Type.ARRAY, 
                    items: { type: Type.STRING },
                    description: "For GRAMMAR_BOARD: List of example sentences" 
                  },
                  game_data: {
                    type: Type.OBJECT,
                    properties: {
                      pairs: {
                        type: Type.ARRAY,
                        items: {
                          type: Type.ARRAY,
                          items: { type: Type.STRING } // A pair is array of 2 strings
                        }
                      }
                    },
                    description: "For GAME_ARENA: Logic for the game (e.g. matching pairs)"
                  }
                },
                required: ["type", "title"]
              }
            }
          },
          required: ["unit_title", "timeline"]
        }
      }
    });

    const text = response.text;
    if (!text) {
      console.error("Gemini returned empty text.");
      return null;
    }

    // Parse
    const blueprint = JSON.parse(text) as LessonBlueprint;
    console.log("Gemini Blueprint:", blueprint);
    return blueprint;

  } catch (error) {
    console.error("Gemini Scan Error:", error);
    throw error;
  }
};

