import React, { useState, useEffect } from 'react';
import { 
  ChevronLeft, Save, Play, Search, Image as ImageIcon, Music, 
  MoreVertical, Plus, Wand2, X, Move, Eye, Loader2, FileText, 
  Sparkles, Layers, Clock, AlertCircle, CheckCircle2, MonitorPlay
} from 'lucide-react';
import { generateSong, generateImage } from '../../services/geminiService';
import { useSession } from '../../store/SessionContext';

interface LessonStudioProps {
  onLaunchLive?: () => void;
}

type BlockType = 'MEDIA_PLAYER' | 'FOCUS_CARDS' | 'GRAMMAR_BOARD' | 'GAME_ARENA' | 'STORY_STAGE' | 'INPUT' | 'PRACTICE' | 'ASSESSMENT' | 'GAP';

// This mirrors the structure in MockEngine but adapted for the UI state
interface TimelineBlock {
  id: string;
  type: BlockType;
  title: string;
  duration: number;
  assetType: 'audio' | 'image' | 'text' | 'game';
  status: 'ready' | 'review' | 'generating';
  data?: any; // The underlying payload
}

const LessonStudio: React.FC<LessonStudioProps> = ({ onLaunchLive }) => {
  const { state, saveUnit } = useSession();
  const activeUnit = state.activeUnit;

  const [activeBlockId, setActiveBlockId] = useState<string | null>(null);
  const [inspectorTab, setInspectorTab] = useState<'preview' | 'edit' | 'ai'>('preview');

  // Prompts state
  const [songPrompt, setSongPrompt] = useState('');
  const [imagePrompt, setImagePrompt] = useState('');
  const [isGenerating, setIsGenerating] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  // The local mutable version of the lesson flow
  const [timeline, setTimeline] = useState<TimelineBlock[]>([]);

  // Load the unit's flow into local state
  useEffect(() => {
    if (activeUnit) {
       if (activeUnit.flow && activeUnit.flow.length > 0) {
          // Map persistent DB flow to UI TimelineBlock
          // If the flow items don't have IDs (mock data), generate them
          const mappedFlow: TimelineBlock[] = activeUnit.flow.map((item: any, idx: number) => ({
             id: item.id || `step_${idx}`,
             type: item.type as BlockType,
             title: item.title,
             duration: item.duration ? Math.round(item.duration / 60) : 5,
             assetType: item.type.includes('MEDIA') ? 'audio' : item.type.includes('CARD') ? 'image' : 'game',
             status: 'ready',
             data: item.data
          }));
          setTimeline(mappedFlow);
          if (mappedFlow.length > 0) setActiveBlockId(mappedFlow[0].id);
       } else if (activeUnit.scannedBlueprint && activeUnit.scannedBlueprint.timeline.length > 0) {
          // NEW: DEEP PARSE INGESTION
          // Map the high-fidelity AI blueprint to our timeline

          const blueprintBlocks: TimelineBlock[] = activeUnit.scannedBlueprint.timeline.map((item, idx) => {
             // Map AI types to UI types
             let assetType: TimelineBlock['assetType'] = 'text';
             if (item.type === 'MEDIA_PLAYER') assetType = 'audio';
             else if (item.type === 'FOCUS_CARDS') assetType = 'image';
             else if (item.type === 'GAME_ARENA') assetType = 'game';

             return {
                id: `ai_${idx}`,
                type: item.type,
                title: item.title,
                duration: 5, // Default duration, AI could provide this later
                assetType: assetType,
                status: 'review', // New AI items need review
                data: item // Pass full AI item as data for now
             };
          });

          setTimeline(blueprintBlocks);
          if (blueprintBlocks.length > 0) setActiveBlockId(blueprintBlocks[0].id);

       } else if (activeUnit.scannedAssets && activeUnit.scannedAssets.length > 0) {
          // LEGACY FALLBACK: Simple asset list
          const generatedBlocks: TimelineBlock[] = [];

          generatedBlocks.push({
             id: 'auto_1', type: 'MEDIA_PLAYER', title: `Intro: ${activeUnit.topic || 'New Topic'}`, duration: 5, assetType: 'audio', status: 'review'
          });

          const vocabAssets = activeUnit.scannedAssets.filter(a => a.type === 'vocab');
          if (vocabAssets.length > 0) {
             generatedBlocks.push({
                id: 'auto_2', type: 'FOCUS_CARDS', title: 'Vocabulary Focus', duration: 10, assetType: 'image', status: 'ready',
                data: { cards: vocabAssets.map(a => a.content) }
             });
          }

          setTimeline(generatedBlocks);
          if (generatedBlocks.length > 0) setActiveBlockId(generatedBlocks[0].id);
       } else {
          // Fallback empty state
          setTimeline([]);
       }
    }
  }, [activeUnit?.id]);

  const activeBlock = timeline.find(b => b.id === activeBlockId);
  const totalDuration = timeline.reduce((acc, b) => acc + (b.type !== 'GAP' ? b.duration : 0), 0);

  const handleGenerateSong = async () => {
    if (!songPrompt || !activeBlockId) return;
    setIsGenerating(true);
    const result = await generateSong(songPrompt);
    setIsGenerating(false);
    if (result) {
      updateBlock(activeBlockId, { 
         title: `Song: ${result.title}`, 
         data: { ...activeBlock?.data, lyrics: result.lyrics, title: result.title },
         status: 'ready' 
      });
      setInspectorTab('preview');
    }
  };

  const updateBlock = (id: string, updates: Partial<TimelineBlock>) => {
    setTimeline(prev => prev.map(b => b.id === id ? { ...b, ...updates } : b));
  };

  const handleSave = async () => {
     if (!activeUnit) return;
     setIsSaving(true);

     // Convert UI Timeline back to DB Schema
     const dbFlow = timeline.map(block => ({
