import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GEMINI_FLASH_MODEL } from "../constants";

// Initialize the client only if the key exists
const getClient = (): GoogleGenAI => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY environment variable is not defined");
  }
  return new GoogleGenAI({ apiKey });
};

export const generateText = async (prompt: string): Promise<string | undefined> => {
  try {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: GEMINI_FLASH_MODEL,
      contents: prompt,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export interface GeneratedSong {
  title: string;
  lyrics: string;
}

export const generateSong = async (topic: string): Promise<GeneratedSong | null> => {
  try {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: GEMINI_FLASH_MODEL,
      contents: `Write a short, catchy ESL song for kids about: ${topic}. Include a Title, Verse 1, and Chorus. Keep vocabulary simple.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING, description: "Catchy song title" },
            lyrics: { type: Type.STRING, description: "Full lyrics including Verse and Chorus markers" }
          },
          required: ["title", "lyrics"]
        }
      }
    });
    const text = response.text;
    if (!text) return null;
    return JSON.parse(text) as GeneratedSong;
  } catch (error) {
    console.error("Gemini Song Gen Error:", error);
    return null;
  }
};

export const generateImage = async (prompt: string): Promise<string | null> => {
  try {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: prompt,
    });

    if (response.candidates?.[0]?.content?.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
    return null;
  } catch (error) {
    console.error("Gemini Image Gen Error:", error);
    return null;
  }
};

export interface PronunciationResult {
  score: number;
  feedback: string;
  wordScores: { text: string; score: 'high' | 'medium' | 'low' }[];
}

export const checkPronunciation = async (audioBase64: string, targetText: string): Promise<PronunciationResult | null> => {
  try {
    const ai = getClient();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'audio/webm',
              data: audioBase64
            }
          },
          {
            text: `Assess the pronunciation of this audio against the target sentence: "${targetText}". 
            Return a JSON object with:
            - 'score' (0-100 integer)
            - 'feedback' (short, encouraging feedback for a child)
            - 'wordScores' (array of objects with 'text' and 'score' which is one of 'high', 'medium', 'low'). 
            Ensure every word in the target sentence is in wordScores.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            score: { type: Type.INTEGER },
            feedback: { type: Type.STRING },
            wordScores: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  score: { type: Type.STRING, enum: ["high", "medium", "low"] }
                }
              }
            }
          }
        }
      }
    });

    const text = response.text;
    if (!text) return null;
    return JSON.parse(text) as PronunciationResult;
  } catch (error) {
    console.error("Gemini Pronunciation Error:", error);
    return null;
  }
};

