// --- CORE TYPES: THE LESSON MANIFEST ---

export interface CharacterProfile {
  name: string;
  visual_traits: string[]; // e.g., "Red hat", "Robot"
  personality?: string;
}

export interface RichVocabItem {
  word: string;
  definition: string;
  context_sentence?: string;
  distractors: string[]; // Critical for Game Generation (Wrong answers)
  image_prompt?: string; // AI suggestion for generating this asset
}

export interface ActivityBlock {
  type: 'MEDIA_PLAYER' | 'FOCUS_CARDS' | 'GRAMMAR_BOARD' | 'GAME_ARENA' | 'STORY_STAGE';
  title: string;
  duration: number;
  config: any; // Flexible payload for specific engines
}

export interface LessonManifest {
  meta: {
    unit_title: string;
    theme: string; // e.g., "Jungle", "Space"
    difficulty_cefr: "Pre-A1" | "A1" | "A2" | "B1";
  };
  knowledge_graph: {
    characters: CharacterProfile[];
    vocabulary: RichVocabItem[];
    grammar_rules: { rule: string; examples: string[] }[];
    narrative_arc?: string; // Summary of the story
  };
  timeline: ActivityBlock[];
}

// --- SYSTEM PROMPT: THE DIRECTOR ---

const DIRECTOR_SYSTEM_PROMPT = `
You are a Senior Educational Game Director & Orchestrator.
Your goal is NOT just to digitize a textbook page, but to "Game-ify" it.
Analyze the provided image and extract a 'LessonManifest'.

### PHASE 1: VISUAL DECONSTRUCTION
1.  **Detect Theme:** Look at the background/art. Is it a Jungle? Space? A City?
2.  **Detect Characters:** Identify recurring characters. Describe them (e.g., "Boy with red cap").
3.  **Detect Logic:**
    *   If you see a Maze, identify the Start and Goal.
    *   If you see a Matching exercise, identify the pairs.

### PHASE 2: ASSET FABRICATION (Crucial)
For every Vocabulary word you find, you MUST invent 3 "Distractors" (wrong answers) for a multiple-choice game.
*   Input: "Elephant"
*   Output Distractors: ["Ant", "Chair", "Cloud"] (Contextually relevant but clearly wrong).

### PHASE 3: ORCHESTRATION (The Timeline)
Construct a 45-minute lesson flow.
*   **Warm Up:** Always start with a song/video related to the Theme.
*   **Input:** Use 'FOCUS_CARDS' for vocabulary.
*   **Practice:** Use 'GAME_ARENA' for the mechanics found on the page.
*   **Application:** Use 'STORY_STAGE' if there is a comic strip.

### OUTPUT FORMAT
Return a purely JSON object matching the LessonManifest schema.
`;

// --- MAIN FUNCTIONS ---

export const analyzeTextbookPage = async (imageBase64: string): Promise<LessonManifest | null> => {
  try {
    const ai = getClient();

    // Schema Definition for Strict JSON
    const responseSchema: Schema = {
      type: Type.OBJECT,
      properties: {
        meta: {
          type: Type.OBJECT,
          properties: {
            unit_title: { type: Type.STRING },
            theme: { type: Type.STRING },
            difficulty_cefr: { type: Type.STRING, enum: ["Pre-A1", "A1", "A2", "B1"] }
          },
          required: ["unit_title", "theme"]
        },
        knowledge_graph: {
          type: Type.OBJECT,
          properties: {
            characters: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  visual_traits: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
              }
            },
            vocabulary: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  word: { type: Type.STRING },
                  definition: { type: Type.STRING },
                  distractors: { type: Type.ARRAY, items: { type: Type.STRING }, description: "3 wrong answers for quizzes" },
                  image_prompt: { type: Type.STRING, description: "A prompt to generate an icon for this word" }
                }
              }
            },
            grammar_rules: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: { rule: { type: Type.STRING }, examples: { type: Type.ARRAY, items: { type: Type.STRING } } }
              }
            }
          },
          required: ["vocabulary"]
        },
        timeline: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, enum: ['MEDIA_PLAYER', 'FOCUS_CARDS', 'GRAMMAR_BOARD', 'GAME_ARENA', 'STORY_STAGE'] },
              title: { type: Type.STRING },
              duration: { type: Type.INTEGER },
              config: { 
                 type: Type.OBJECT, 
                 properties: {
                    search_query: { type: Type.STRING },
                    items: { type: Type.ARRAY, items: { type: Type.STRING } },
                    game_mode: { type: Type.STRING },
                    pairs: { type: Type.ARRAY, items: { type: Type.ARRAY, items: { type: Type.STRING } } } 
                 } 
              }
            },
            required: ["type", "title"]
          }
        }
      },
      required: ["meta", "knowledge_graph", "timeline"]
    };

    const response = await ai.models.generateContent({
      model: GEMINI_PRO_MODEL,
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: imageBase64 } },
          { text: "Analyze this textbook page and generate a Director's Manifest." }
        ]
      },
      config: {
        systemInstruction: DIRECTOR_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    const text = response.text;
    if (!text) return null;

    const manifest = JSON.parse(text) as LessonManifest;

    // Post-Process: Run the "Asset Factory" to fill gaps if necessary
    // (e.g., if distractors are missing, generate them now)
    const enrichedManifest = await fillContentGaps(manifest);

    return enrichedManifest;

  } catch (error) {
    console.error("Gemini Director Error:", error);
    throw error;
  }
};

