import { GoogleGenAI, Type, Schema } from "@google/genai";
import { GEMINI_FLASH_MODEL, GEMINI_PRO_MODEL } from "../constants";

// Initialize the client
const getClient = (): GoogleGenAI => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY environment variable is not defined");
  }
  return new GoogleGenAI({ apiKey });
};

// --- CORE TYPES: THE LESSON MANIFEST ---

export interface CharacterProfile {
  name: string;
  visual_traits: string[]; 
  personality?: string;
}

export interface RichVocabItem {
  word: string;
  definition: string;
  context_sentence?: string;
  distractors: string[]; 
  image_prompt?: string;
}

export interface ActivityBlock {
  type: 'MEDIA_PLAYER' | 'FOCUS_CARDS' | 'GRAMMAR_BOARD' | 'GAME_ARENA' | 'STORY_STAGE';
  title: string;
  duration: number;
  config: any;
}

export interface LessonManifest {
  meta: {
    unit_title: string;
    theme: string; 
    difficulty_cefr: "Pre-A1" | "A1" | "A2" | "B1";
  };
  knowledge_graph: {
    characters: CharacterProfile[];
    vocabulary: RichVocabItem[];
    grammar_rules: { rule: string; examples: string[] }[];
    narrative_arc?: string; 
  };
  timeline: ActivityBlock[];
