export const transformManifestToFlow = (manifest: LessonManifest): any[] => {

  // 1. Create Intro Splash
  const introSlide = {
    id: 'step_intro',
    type: 'INTRO_SPLASH',
    title: `Welcome to ${manifest.meta.unit_title}`,
    duration: 5,
    data: { theme: manifest.meta.theme }
  };

  // 2. Transform Timeline Items
  const flowSlides = manifest.timeline.map((block, index) => {
    const stepId = `step_${index + 1}`;

    switch (block.type) {
      case 'MEDIA_PLAYER':
        return {
          id: stepId,
          type: 'MEDIA_PLAYER',
          title: block.title,
          duration: block.duration || 300,
          teacherGuide: {
            instruction: "Play the video to introduce the topic.",
            script: `Let's watch a video about ${manifest.meta.theme}.`,
          },
          data: {
            title: block.title,
            // If AI didn't provide a specific URL, fallback to search query logic
            videoThumbnail: getAssetUrl(block.config?.search_query || manifest.meta.theme),
            // Mock lyrics generation based on theme
            lyrics: [] 
          }
        };

      case 'FOCUS_CARDS':
        // Map Vocabulary from Knowledge Graph to Cards
        // We use the full Knowledge Graph to hydrate the cards, not just the config items
        const vocabItems = manifest.knowledge_graph.vocabulary;
        return {
          id: stepId,
          type: 'FOCUS_CARDS',
          title: block.title,
          duration: block.duration || 300,
          teacherGuide: {
            instruction: "Drill pronunciation. Use the 'Flip' button to reveal the word.",
            script: "Repeat after me.",
          },
          data: {
            title: "New Vocabulary",
            cards: vocabItems.map((v, i) => ({
              id: `c_${i}`,
              front: v.image_prompt ? '🎨' : '📸', // Icon placeholder if no real image
              back: v.word,
              pronunciation: `/${v.word.toLowerCase()}/`, // Mock phonetic
              image: getAssetUrl(v.word) // Hydrate with visual
            }))
          }
        };

      case 'GAME_ARENA':
        // Generate Quiz Questions from Vocabulary + Distractors
        const quizQuestions = manifest.knowledge_graph.vocabulary.slice(0, 5).map((v, i) => ({
          id: `q_${i}`,
          text: `Which one is the ${v.word}?`,
          image: getAssetUrl(v.word),
          options: [v.word, ...(v.distractors || ['Option A', 'Option B', 'Option C'])].sort(() => Math.random() - 0.5),
          correct: v.word
        }));

        return {
          id: stepId,
          type: 'TEAM_BATTLE', // Map GAME_ARENA to TEAM_BATTLE for the prototype board
          title: block.title,
          duration: block.duration || 600,
          teacherGuide: {
            instruction: "Divide class into Red vs Blue teams.",
            script: "Who knows the answer? Team Red?",
            answerKey: quizQuestions.map(q => q.correct).join(', ')
          },
          data: {
            topic: manifest.meta.theme,
            questions: quizQuestions
          }
        };

      case 'STORY_STAGE':
        return {
          id: stepId,
          type: 'STORY_STAGE',
          title: block.title,
          duration: block.duration || 600,
          teacherGuide: {
            instruction: "Read aloud, then assign roles.",
            script: "Let's see what happens next.",
          },
          data: {
            // Mocking pages structure since Manifest 'config' might be simple
            pages: [
              { id: 'p1', text: "One day in the " + manifest.meta.theme + "..." },
              { id: 'p2', text: "Suddenly, something happened!" },
              { id: 'p3', text: "The end." }
            ]
          }
        };

      default:
        // Fallback for unknown types
        return {
          id: stepId,
          type: 'INTRO_SPLASH', // Safe fallback
          title: block.title,
          duration: block.duration,
          data: { theme: block.title }
        };
    }
  });

  return [introSlide, ...flowSlides];
};

