    setTimeout(() => {
       setIsSpinning(false);
    }, 2000);
  };

  // Group Logic
  const generateGroups = () => {
    const shuffled = [...MOCK_STUDENTS].sort(() => Math.random() - 0.5);
    const newGroups: any[][] = Array.from({ length: groupCount }, () => []);
    shuffled.forEach((student, index) => {
