// --- UTILITIES: THE CLEANER ---

/**
 * Strips markdown code blocks (```json ... ```) from the response text
 * to ensure JSON.parse doesn't choke.
 */
const cleanJsonText = (text: string): string => {
  if (!text) return "{}";
  let clean = text.trim();
  // Remove markdown wrapping
  if (clean.startsWith("```json")) {
    clean = clean.replace(/^```json\s*/, "").replace(/\s*```$/, "");
  } else if (clean.startsWith("```")) {
    clean = clean.replace(/^```\s*/, "").replace(/\s*```$/, "");
  }
  return clean;
};

/**
 * Generates a "Safety Net" manifest if the AI fails completely.
 * This ensures the UI never breaks.
 */
const createFallbackManifest = (): LessonManifest => ({
  meta: {
    unit_title: "New Lesson Scan",
    theme: "General",
    difficulty_cefr: "A1"
  },
  knowledge_graph: {
