// --- SYSTEM PROMPT ---

const DIRECTOR_SYSTEM_PROMPT = `
You are an expert ESL Lesson Architect. Analyze the image and output a JSON object.
CRITICAL: You must generate a 'timeline' array with at least 4 activities.

1. Detect the Theme (e.g. 'Jungle', 'Airport').
2. Extract Vocabulary (list of words).
3. Create a Timeline. Use EXACTLY these types:
   - 'MEDIA_PLAYER' (for songs/videos)
   - 'FOCUS_CARDS' (for vocab teaching)
   - 'GRAMMAR_BOARD' (for rules)
   - 'GAME_ARENA' (for quizzes)
   - 'STORY_STAGE' (for reading)

Structure the JSON exactly like this schema. Do not wrap in markdown.
`;

// --- MAIN FUNCTIONS ---

export const analyzeTextbookPage = async (imageBase64: string): Promise<LessonManifest | null> => {
  try {
    const ai = getClient();

    // Strict Schema Definition
    const responseSchema: Schema = {
      type: Type.OBJECT,
      properties: {
        meta: {
          type: Type.OBJECT,
          properties: {
            unit_title: { type: Type.STRING },
            theme: { type: Type.STRING },
            difficulty_cefr: { type: Type.STRING, enum: ["Pre-A1", "A1", "A2", "B1"] }
          },
          required: ["unit_title", "theme"]
        },
        knowledge_graph: {
          type: Type.OBJECT,
          properties: {
            characters: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  visual_traits: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
              }
            },
            vocabulary: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  word: { type: Type.STRING },
                  definition: { type: Type.STRING },
                  distractors: { type: Type.ARRAY, items: { type: Type.STRING } },
                  image_prompt: { type: Type.STRING }
                }
              }
            },
            grammar_rules: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: { rule: { type: Type.STRING }, examples: { type: Type.ARRAY, items: { type: Type.STRING } } }
              }
            }
          },
          required: ["vocabulary"]
        },
        timeline: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING, enum: ['MEDIA_PLAYER', 'FOCUS_CARDS', 'GRAMMAR_BOARD', 'GAME_ARENA', 'STORY_STAGE'] },
              title: { type: Type.STRING },
              duration: { type: Type.INTEGER },
              config: { 
                 type: Type.OBJECT, 
                 properties: {
                    search_query: { type: Type.STRING },
                    items: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { word: { type: Type.STRING } } } },
                    game_mode: { type: Type.STRING }
                 } 
              }
            },
            required: ["type", "title"]
          }
        }
      },
      required: ["meta", "knowledge_graph", "timeline"]
    };

    const response = await ai.models.generateContent({
      model: GEMINI_FLASH_MODEL,
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: imageBase64 } },
          { text: "Analyze this page. Return valid JSON matching the LessonManifest schema. Ensure the timeline array is populated." }
        ]
      },
      config: {
        systemInstruction: DIRECTOR_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: responseSchema
      }
    });

    const rawText = response.text;
    console.log("Raw Gemini Output:", rawText); // Debugging

    if (!rawText) throw new Error("Empty response from AI");

    const cleanText = cleanJsonText(rawText);
    let manifest: LessonManifest;

    try {
      manifest = JSON.parse(cleanText) as LessonManifest;
    } catch (parseError) {
      console.error("JSON Parse Failed:", parseError);
      // Fallback: If JSON is malformed, use safety net
      return createFallbackManifest();
    }

    // Post-Process: Validation & Repair
    // If timeline is empty, auto-generate one from vocabulary
    if (!manifest.timeline || manifest.timeline.length === 0) {
       console.warn("AI returned empty timeline. Auto-generating...");
       manifest.timeline = [
         {
           type: 'MEDIA_PLAYER',
           title: `Intro to ${manifest.meta.theme}`,
           duration: 5,
           config: { search_query: `${manifest.meta.theme} song for kids` }
         },
         {
           type: 'FOCUS_CARDS',
           title: 'Vocabulary Drill',
           duration: 10,
           config: { items: manifest.knowledge_graph.vocabulary }
         }
       ];
    }

    // Run the asset factory to fill remaining gaps (distractors, etc)
    const enrichedManifest = await fillContentGaps(manifest);
    return enrichedManifest;

  } catch (error) {
    console.error("Gemini Director Critical Failure:", error);
    // Return fallback so the app doesn't crash
    return createFallbackManifest();
  }
};

/**
 * The "Asset Factory" - GAP FILLER
 */
const fillContentGaps = async (manifest: LessonManifest): Promise<LessonManifest> => {
  // 1. Ensure vocabulary has distractors
  if (manifest.knowledge_graph?.vocabulary) {
    manifest.knowledge_graph.vocabulary = manifest.knowledge_graph.vocabulary.map(v => {
      // Clean up word objects if they are strings (schema drift protection)
      if (typeof v === 'string') return { word: v, definition: '', distractors: ["Option A", "Option B"] };

      const hasDistractors = v.distractors && v.distractors.length >= 3;
      return {
        ...v,
        distractors: hasDistractors ? v.distractors : ["Apple", "Blue", "Car"] // Generic fallback
      };
    });
  } else {
    manifest.knowledge_graph.vocabulary = [];
  }

  // 2. Ensure Timeline Configs are populated
  manifest.timeline = manifest.timeline.map(block => {
    // If FOCUS_CARDS block has no items, inject all vocabulary
    if (block.type === 'FOCUS_CARDS' && (!block.config?.items || block.config.items.length === 0)) {
        return { 
            ...block, 
            config: { ...block.config, items: manifest.knowledge_graph.vocabulary } 
        };
    }
    // If GAME_ARENA has no topic, use theme
    if (block.type === 'GAME_ARENA' && !block.config?.game_mode) {
        return {
            ...block,
            config: { ...block.config, game_mode: 'QUIZ', topic: manifest.meta.theme }
        };
    }
    return block;
  });

  return manifest;
};

