const pipelineSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    agent_1_vision: {
      type: Type.OBJECT,
      properties: {
        detected_zones: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              id: { type: Type.STRING },
              type: { type: Type.STRING, enum: ['VISUAL_PUZZLE', 'COMIC_STRIP', 'GRAMMAR_TABLE', 'SONG_SHEET', 'VOCAB_LIST', 'READING_PASSAGE', 'ILLUSTRATION'] },
              description: { type: Type.STRING },
              text_content: { type: Type.STRING }
            },
            required: ["id", "type", "description"]
          }
        },
        overall_layout: { type: Type.STRING },
        dominating_visual: { type: Type.STRING }
      },
      required: ["detected_zones"]
    },
    agent_2_pedagogy: {
      type: Type.OBJECT,
      properties: {
        primary_topic: { type: Type.STRING },
        grammar_focus: { type: Type.STRING },
        target_skills: { type: Type.ARRAY, items: { type: Type.STRING } },
        difficulty_cefr: { type: Type.STRING, enum: ['Pre-A1', 'A1', 'A2', 'B1'] },
        educational_goal: { type: Type.STRING }
      },
      required: ["primary_topic", "educational_goal"]
    },
    agent_3_assets: {
      type: Type.OBJECT,
      properties: {
