      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          engine: { type: Type.STRING, enum: ['LOGIC_LABYRINTH', 'SENTENCE_FACTORY', 'DUBBING_STUDIO', 'FLASH_MATCH', 'MEDIA_PLAYER'] },
