export const analyzeTextbookPage = async (imageBase64: string): Promise<LessonManifest | null> => {
  try {
    const ai = getClient();

    // Use Pro model for high intelligence reasoning
    const response = await ai.models.generateContent({
      model: GEMINI_PRO_MODEL, 
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: imageBase64 } },
          { text: "Execute the 5-Agent Pipeline." }
        ]
      },
      config: {
        systemInstruction: MULTI_AGENT_SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: pipelineSchema
      }
    });

    const rawText = response.text;
    if (!rawText) throw new Error("Empty response from Gemini");

    // Clean markdown if present
    const cleanText = rawText.replace(/^```json\s*/, "").replace(/\s*```$/, "");

    const pipelineOutput = JSON.parse(cleanText) as AgentPipelineOutput;

    console.log("Pipeline Success! Detected Zones:", pipelineOutput.agent_1_vision.detected_zones.length);
    console.log("Orchestrator Plan:", pipelineOutput.agent_5_orchestrator.timeline.length);

    // Return the final orchestrator output, enriched with the detailed agent data if needed.
    // For now, the App expects a LessonManifest structure.
    // We can inject the deep data into the knowledge_graph of the manifest if we update the type,
    // but to fit the existing app, we return the orchestrator's output.

    // We need to map the pipeline output to the 'LessonManifest' interface the app expects.
