  "overall_layout": "Mixed media textbook page",
  "detected_zones": [
    {
      "id": "zone_1",
      "type": "MEDIA_LINK",
      "description": "Video prompt icon",
      "coordinates_hint": "Top-Left"
    },
    {
      "id": "zone_2",
      "type": "GRAMMAR_TABLE",
      "description": "Box titled 'Gracie's Grammar'",
      "text_content": "I like... / I don't like..."
    },
    {
      "id": "zone_3",
      "type": "VISUAL_PUZZLE",
      "description": "Maze connecting animals to habitats",
